const ctx = $('When Called by Router').item.json;
const cita = $input.first().json;

let msgCita = '';
if (cita?.fecha) {
  const fechaObj = new Date(cita.fecha + 'T12:00:00');
  const opciones = { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'UTC' };
  const fechaLegible = fechaObj.toLocaleDateString('es-ES', opciones);
  msgCita = `📅 Tu cita está agendada para el *${fechaLegible}* a las *${cita.hora_inicio} hrs*.`;
} else {
  msgCita = '📅 Tienes una cita agendada próximamente.';
}

const msgFinal = `Hola ${ctx.client_name}, ¡ya tienes una cita con nosotros! 🎉\n\n${msgCita}\n\nSi necesitas cambiar o cancelar tu cita, escríbenos con anticipación. ¡Te esperamos! ⚖️`;

return [{ json: { ...ctx, mensaje_ya_cita: msgFinal } }];
